#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e7+10;int pm[N>>3],cpt,dp[N];short mu[N];bool vs[N];
inline void Init(int w=1e7)
{
	mu[1]=1;vs[1]=1;rep(2,w,i)
	{
		if(!vs[i])dp[pm[++cpt]=i]=1,mu[i]=-1;
		for(int j=1;j<=cpt&&pm[j]*i<=w;++j)
		{
			vs[pm[j]*i]=true;
			if(i%pm[j]==0){dp[i*pm[j]]=mu[i];mu[i*pm[j]]=0;break;}
			dp[i*pm[j]]=-dp[i]+mu[i];mu[pm[j]*i]=-mu[i];
		}
		dp[i]+=dp[i-1];
	}
}
inline void Solve()
{
	int n=read(),m=read();if(n>m){int t(n);n=m;m=t;} long long ans=0;
	for(int l=1,r=0;l<=n;l=r+1){r=min(n/(n/l),m/(m/l));ans+=1ll*(dp[r]-dp[l-1])*(n/l)*(m/l);}
	printf("%lld\n",ans);return;
}
int main(){Init();int T=read();while(T--)Solve();}
